import type { ScaleLinear, ScaleLogarithmic, ScaleSymLog } from 'd3-scale';
import type { ChartUnit } from '../../core/types/chart-unit.js';
import type { ColorToken } from '../../core/types/color-palette.js';
/**
 * @public
 */
export type HistogramZoomDomain = number[];
